import{_ as o,o as s,c as d,a2 as e}from"./chunks/framework.BWuWLRhz.js";const n="/assets/03-agent-loop@2x.qymDYriP.png",u=JSON.parse('{"title":"03 · Claude Code 如何工作","description":"","frontmatter":{"head":[["meta",{"property":"og:site_name","content":"David Studio AI 编程指南"}]]},"headers":[],"relativePath":"claude-code/03-how-it-works.md","filePath":"claude-code/03-how-it-works.md"}'),r={name:"claude-code/03-how-it-works.md"};function a(p,t,l,g,i,c){return s(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="_03-·-claude-code-如何工作" tabindex="-1">03 · Claude Code 如何工作 <a class="header-anchor" href="#_03-·-claude-code-如何工作" aria-label="Permalink to &quot;03 · Claude Code 如何工作&quot;">​</a></h1><blockquote><p>📚 <strong>系列导航</strong>：上一篇 <a href="./02-install">02 · 安装与使用</a> 带你把 Claude Code 装好、跑起来。这一篇拆开盖子，看清它到底怎么干活——为什么它能自己读代码、改文件、跑命令，而不只是聊天。</p></blockquote><p>第一次用 Claude Code，常会撞见这么一段对话——</p><blockquote><p>你：「这个测试为啥挂了？」 Claude：「我先跑一下测试套件看看。」（开始跑命令） Claude：「报错说 <code>validateEmail</code> 返回了 undefined，我去看看这个函数。」（读了文件） Claude：「找到了，这里少了一个 return。我改一下，然后重新跑测试确认。」（改完，又跑了一次） Claude：「测试过了。」</p></blockquote><p>看到这儿容易有点懵：<strong>只问了一句话，它怎么自己跑命令、自己读文件、自己改、还自己验证了？</strong></p><p>说白了，这就是 Claude Code 和普通 AI 聊天框最大的区别。聊天框只会「回你一段文字」，而 Claude Code 会<strong>自己动手做事</strong>。这背后是一套固定的工作机制，今天讲透。</p><p><strong>看完这一篇，你会拿到：</strong></p><ul><li>一张图看懂 Claude Code 的「代理循环」——它每做一件事都在重复的三个动作</li><li>搞清楚它手里那 5 类「工具」分别能干啥，以及它怎么决定用哪个</li><li>知道它到底能看到你电脑上的什么、看不到什么（关系到安全）</li><li>一个能照着跑的小实验，亲眼看它走完一整个循环</li></ul><hr><h2 id="_01-代理循环-想-→-做-→-看" tabindex="-1">01 代理循环：想 → 做 → 看 <a class="header-anchor" href="#_01-代理循环-想-→-做-→-看" aria-label="Permalink to &quot;01 代理循环：想 → 做 → 看&quot;">​</a></h2><p>先说结论：<strong>Claude Code 干任何活，都在重复三个动作——收集上下文、采取行动、验证结果</strong>。官方把这套机制叫「代理循环（agentic loop）」。</p><p>换个更土的说法：<strong>想 → 做 → 看</strong>。</p><ul><li><strong>想</strong>（收集上下文）：先搞清楚状况——读相关文件、看报错、查 git 状态</li><li><strong>做</strong>（采取行动）：动手——改代码、跑命令、新建文件</li><li><strong>看</strong>（验证结果）：检查刚才做的对不对——跑测试、看输出，不对就再来一轮</li></ul><p><strong>类比：一个靠谱的修车师傅。</strong> 你把车开进店说「方向盘抖」，师傅不会立刻拆。他先<strong>看一圈、试开两步</strong>（想），再<strong>动扳手</strong>（做），修完<strong>开一段确认不抖了</strong>（看）。还抖就回第一步重查。Claude Code 就是这么个师傅，只不过修的是你的代码。</p><p>回到开头那段对话，对照一下你就懂了：</p><table tabindex="0"><thead><tr><th>Claude 说的话</th><th>对应循环里的哪一步</th></tr></thead><tbody><tr><td>「我先跑一下测试套件」</td><td>想（收集上下文）</td></tr><tr><td>「报错说 undefined，我去看看这个函数」</td><td>想（继续收集）</td></tr><tr><td>「这里少了 return，我改一下」</td><td>做（采取行动）</td></tr><tr><td>「然后重新跑测试确认」</td><td>看（验证结果）</td></tr><tr><td>「测试过了」</td><td>循环结束</td></tr></tbody></table><p>它把这三步<strong>串成一条链</strong>，一步的结果决定下一步干什么。修个 bug 可能循环好几轮，问个「这段代码啥意思」可能只要「想」这一步就够。<strong>循环几轮，由任务复杂度决定，不是写死的。</strong></p><p><img src="'+n+`" alt="代理循环：想 → 做 → 看"></p><p>上面这张图就是 Claude Code 每次干活转的圈：从「想」到「做」到「看」，不满意就从「看」拐回「想」再来一轮——你随时能按 <code>Esc</code> 把它叫停。</p><p>这里有个关键点，很多人没意识到：<strong>你也是这个循环的一部分</strong>。它走偏了，你随时能插话纠正——这点下一节细说。</p><p>驱动这个循环的是两样东西：<strong>模型负责「想」，工具负责「做」和「看」</strong>。</p><p>模型就是 Claude 的大脑——Sonnet 应付日常编程够用，Opus 推理更强、适合复杂架构。会话里输入 <code>/model</code> 随时切，或者启动时 <code>claude --model sonnet</code>。</p><blockquote><p>💡 <strong>一句话总结</strong>：Claude Code 不是「回你一段话」，而是「想→做→看」转圈直到把事办完，<strong>这才是它和聊天框的本质区别</strong>。</p></blockquote><hr><h2 id="_02-你也在循环里-随时能打断" tabindex="-1">02 你也在循环里：随时能打断 <a class="header-anchor" href="#_02-你也在循环里-随时能打断" aria-label="Permalink to &quot;02 你也在循环里：随时能打断&quot;">​</a></h2><p>上一节结尾说了：你也是这个循环的一部分。展开聊聊。普通 AI 聊天是「你问一句、它答一段、回合结束」。Claude Code 不一样——它在循环里自己跑的时候，<strong>你不用干等着，随时能插手</strong>。</p><p>比如让它重构一个模块，看它跑偏了、正要大改一堆文件，直接按 <code>Esc</code>，它立刻停下，正在跑的命令也取消了。再补一句「别动那个文件，只改这个函数」，它就顺着新指示继续。</p><p>两种打断方式，区别要分清：</p><table tabindex="0"><thead><tr><th>操作</th><th>效果</th><th>什么时候用</th></tr></thead><tbody><tr><td>按 <code>Esc</code></td><td><strong>立刻停</strong>，正在跑的工具调用被取消，等你下一条指令</td><td>它跑偏了、要做的事不对，赶紧拦住</td></tr><tr><td>打字 + <code>Enter</code></td><td><strong>不打断当前操作</strong>，发一句补充，它做完手头的就读</td><td>只是想补个上下文、提个醒，不急着叫停</td></tr></tbody></table><blockquote><p>你不需要憋一个「完美的提示」。先说个大概，看它做，不对再纠正——<strong>这是对话，不是一次性命令</strong>。</p></blockquote><p>这话是官方文档原话，特别值得记住。刚上手时总想「一句话把需求说全」，憋半天。其实没必要：丢个大方向，它做错了再喊停，<strong>迭代比憋大招快得多</strong>。</p><blockquote><p>💡 <strong>一句话总结</strong>：它自主干活，但<strong>永远听你指挥</strong>——<code>Esc</code> 急停、打字补充，方向盘随时在你手里。</p></blockquote><hr><h2 id="_03-工具-它能真正动手的原因" tabindex="-1">03 工具：它能真正动手的原因 <a class="header-anchor" href="#_03-工具-它能真正动手的原因" aria-label="Permalink to &quot;03 工具：它能真正动手的原因&quot;">​</a></h2><p>上一节说模型负责「想」。那「做」和「看」靠什么？<strong>工具。</strong></p><p>这是 Claude Code 最该记住的一句话：<strong>没有工具，Claude 只能回你文字；有了工具，它能真的读你的代码、改你的文件、跑你的命令。</strong></p><p><strong>类比：一个戴了智能手环的助理。</strong> 光会说话的助理只能出主意；给他配上能开门、打字、查资料的设备，他才能真正替你把事办了。工具就是 Claude Code 的「手」。</p><p>官方把内置工具分成 5 大类。我用大白话给你列一遍——</p><table tabindex="0"><thead><tr><th>工具类别</th><th>它能干什么</th><th>对应你平时的什么操作</th></tr></thead><tbody><tr><td><strong>文件操作</strong></td><td>读文件、改代码、新建文件、重命名、重组</td><td>你在编辑器里打开、敲字、保存</td></tr><tr><td><strong>搜索</strong></td><td>按文件名找文件、用正则在内容里搜、翻整个代码库</td><td>你按 <code>Ctrl+F</code> 或 <code>grep</code></td></tr><tr><td><strong>执行</strong></td><td>跑 shell 命令、起服务器、跑测试、用 git</td><td>你在终端里敲命令回车</td></tr><tr><td><strong>网络</strong></td><td>搜网页、抓文档、查报错信息</td><td>你打开浏览器搜一段错误</td></tr><tr><td><strong>代码智能</strong></td><td>看类型错误和警告、跳转定义、查引用</td><td>IDE 的「转到定义」「找引用」</td></tr></tbody></table><blockquote><p>⚠️ <strong>注意</strong>：第 5 类「代码智能」需要额外装<a href="https://code.claude.com/docs/zh-CN/discover-plugins" target="_blank" rel="noreferrer">代码智能插件</a>才有，前 4 类是开箱即用的。以官方文档为准。</p></blockquote><p>那它<strong>怎么决定用哪个工具</strong>？不是你指定的，是<strong>模型自己根据你的话和当前进展挑</strong>。</p><p>举个官方的例子，你说一句「修复失败的测试」，它内部大概会这么走：</p><ol><li>跑测试套件，看哪个挂了 —— 用了 <strong>执行</strong></li><li>读报错输出 —— <strong>执行</strong></li><li>搜相关源文件 —— <strong>搜索</strong></li><li>读这些文件理解逻辑 —— <strong>文件操作</strong></li><li>改文件修 bug —— <strong>文件操作</strong></li><li>再跑一次测试验证 —— <strong>执行</strong></li></ol><p>看出来没？<strong>这 6 步就是「想→做→看」循环在工具层面的展开</strong>。每用一次工具，就拿回一点新信息，喂给模型决定下一步——循环就是这么转起来的。</p><p>有个很典型的场景：让它给一个没文档的老项目「理一下目录结构」。它不用你喂任何文件，自己 <code>ls</code>、自己 <code>grep</code> 关键字、读了七八个文件，最后画出一张结构图。<strong>全程没指定任何一个文件</strong>——这就是官方说的「委派，不要指示」：给方向，细节它自己抠。</p><p>至于 Skill、MCP、Hook、Subagent 这些——它们是<strong>架在这 5 类内置工具之上的扩展层</strong>，能让 Claude 知道更多、连更多外部服务。本系列后面一篇篇讲，先知道有这么回事就行。</p><blockquote><p>💡 <strong>一句话总结</strong>：工具是 Claude Code 的「手」，5 类各管一摊；<strong>用哪个、用几次，它自己决定</strong>，你只管说目标。</p></blockquote><hr><h2 id="_04-它能看到你电脑上的什么" tabindex="-1">04 它能看到你电脑上的什么 <a class="header-anchor" href="#_04-它能看到你电脑上的什么" aria-label="Permalink to &quot;04 它能看到你电脑上的什么&quot;">​</a></h2><p>这一节关系到安全，得说清楚。很多人第一次用会犯嘀咕：<strong>它是不是把我整个硬盘都翻了一遍传走了？</strong> 不是。</p><p>先记一句话：<strong>Claude Code 的「视野」基本等于你在那个目录下的终端能摸到的东西</strong>。你在哪个文件夹敲的 <code>claude</code>，它的活动范围就以那儿为中心。</p><p>按官方文档，当你在某个目录运行 <code>claude</code>，它能访问：</p><ul><li><strong>你的项目</strong>：当前目录和子目录里的文件（其他地方的文件需要你给权限才碰）</li><li><strong>你的终端</strong>：你能跑的任何命令——构建工具、git、包管理器、脚本。<strong>命令行能干的，它就能干</strong></li><li><strong>你的 git 状态</strong>：当前分支、未提交的改动、最近的提交历史</li><li><strong>你的 <code>CLAUDE.md</code></strong>：你写的项目专属说明书，每次会话它都会读（这文件后面有专篇讲）</li><li><strong>你配置的扩展</strong>：MCP、Skill、Subagent 这些</li></ul><p>正因为它能看到<strong>整个项目</strong>，而不只是你当前打开的那一个文件，所以它能跨文件协调——你说「修登录 bug」，它能搜出相关的好几个文件、一起改、再跑测试验证。<strong>这和只看当前文件的内联补全插件，根本不是一回事。</strong></p><p>那安全怎么保证？两道闸——</p><p><strong>第一道：检查点（checkpoint），相当于游戏存档。</strong> 它改任何文件之前，会先给当前内容拍个快照。改坏了，在<strong>输入框空着时连按两次 <code>Esc</code></strong>（或输入 <code>/rewind</code>），会弹出一个「回溯菜单」，选「恢复代码」就把文件退回改之前；也可以直接说「撤销刚才的修改」。</p><blockquote><p><strong>检查点只管 Claude 用编辑工具改的文件——bash 命令改的、以及外部副作用都不在内。</strong> 数据库、API、线上部署这类「泼出去收不回」的操作没法存档——所以 Claude 在跑这类有外部影响的命令前会<strong>先问你</strong>。</p></blockquote><p>这里有个常踩的坑：有时它改了五六个文件，你看完觉得方向全错。搁以前得手动一个个 <code>git checkout</code> 回滚，现在按两下 <code>Esc</code>、在弹出的菜单里选「恢复代码」——<strong>五个文件齐刷刷回到改之前</strong>，干净利落。有了这一手，放手让它改代码就没那么怵了。</p><p><strong>第二道：权限模式，相当于实习生动手前问不问你。</strong> 按 <code>Shift+Tab</code> 循环切换：</p><table tabindex="0"><thead><tr><th>权限模式</th><th>状态栏显示</th><th>Claude 的行为</th></tr></thead><tbody><tr><td><strong>默认</strong></td><td>（不显示提示）</td><td>改文件、跑命令前都会询问你</td></tr><tr><td><strong>自动接受编辑</strong></td><td><code>⏵⏵ accept edits on</code></td><td>改文件和常见文件命令（如 <code>mkdir</code>、<code>mv</code>）不问，其他命令仍问</td></tr><tr><td><strong>Plan Mode（计划模式）</strong></td><td><code>⏸ plan mode on</code></td><td>可读文件和运行探索性命令，但不编辑源代码；先给你一份计划，你批准了才动手</td></tr><tr><td><strong>自动模式</strong></td><td><code>⏵⏵ auto mode on</code></td><td>用后台安全检查评估所有操作（<strong>实验性，目前是研究预览，可能变化</strong>）</td></tr></tbody></table><p>最值得养成的习惯是用 <strong>Plan Mode</strong>：复杂任务先按两下 <code>Shift+Tab</code> 进去，让它「只分析、出方案、别动手」，方案过一遍、改改，确认了再放它执行。<strong>这能躲过好几次「方向错了改一半」的返工</strong>——先看图纸再施工，比边干边改省事太多。</p><p>嫌每次都问烦？可以在项目的 <code>.claude/settings.json</code> 里把信任的命令（比如 <code>npm test</code>、<code>git status</code>）加白名单，以后不问。配置细节后面专篇讲。</p><blockquote><p>💡 <strong>一句话总结</strong>：它的视野≈你在那个目录的终端权限；<strong>检查点管「改坏了能撤」，权限模式管「动手前问不问」</strong>——两道闸下，放手用也踏实。</p></blockquote><hr><h2 id="_05-动手-亲眼看它走一个完整循环" tabindex="-1">05 动手：亲眼看它走一个完整循环 <a class="header-anchor" href="#_05-动手-亲眼看它走一个完整循环" aria-label="Permalink to &quot;05 动手：亲眼看它走一个完整循环&quot;">​</a></h2><p>光看原理记不住，跑一个最小实验，亲眼看它「想→做→看」转一圈。<strong>这个实验不依赖任何现成项目</strong>，新建个空文件夹就能做。</p><p><strong>第一步：建个空目录，进去启动 Claude Code。</strong></p><p>在终端里跑（Mac / Linux；Windows 用 PowerShell 把 <code>mkdir -p</code> 换成 <code>mkdir</code> 即可）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/cc-demo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/cc-demo</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span></span></code></pre></div><p><strong>第二步：进去之后，先切到计划模式看它怎么「想」。</strong></p><p>按两下 <code>Shift+Tab</code>，界面底部会提示进入了 <strong>Plan Mode（计划模式）</strong>。然后丢这么一句给它：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我写一个 Python 脚本 add.py，里面一个函数 add(a, b) 返回两数之和，</span></span>
<span class="line"><span>再写几个测试用例验证它，最后跑一遍测试。先给我计划，别直接动手。</span></span></code></pre></div><p><strong>预期看到</strong>：它<strong>不会</strong>立刻建文件，而是先回你一份计划，大致是——</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>计划：</span></span>
<span class="line"><span>1. 创建 add.py，实现 add(a, b)</span></span>
<span class="line"><span>2. 创建测试（用 assert 或 pytest）</span></span>
<span class="line"><span>3. 运行测试，确认全部通过</span></span>
<span class="line"><span></span></span>
<span class="line"><span>需要我开始吗？</span></span></code></pre></div><p>这就是「想」——它在动手前先理清了思路。<strong>注意它停下来等你批准了，这是计划模式的特征。</strong></p><p><strong>第三步：批准，看它「做」+「看」。</strong></p><p>回复「可以，开始吧」。接着你会看到它依次：</p><ul><li><strong>建文件</strong>（文件操作工具）——可能先弹一下权限确认，你按同意</li><li>写完后<strong>跑测试</strong>（执行工具），比如执行 <code>python add.py</code> 或 <code>pytest</code></li><li>把测试输出贴给你，<strong>预期是类似</strong>：</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>测试通过：add(2, 3) == 5 ✓  add(-1, 1) == 0 ✓  add(0, 0) == 0 ✓</span></span></code></pre></div><p>到这儿，你就完整看了一遍循环：<strong>想（出计划）→ 做（建文件、写代码）→ 看（跑测试报告结果）</strong>。</p><p><strong>第四步（可选）：故意制造一次「再循环」。</strong></p><p>跟它说：「把 add 改成减法，但函数名别变，然后重新跑测试。」</p><p>你会看到它<strong>改完代码、再跑测试</strong>——如果测试断言还是加法，测试会挂，它会<strong>自己发现挂了、回头再改</strong>。这就是循环的精髓：<strong>看到不对，自动再来一轮。</strong></p><p>新手都值得跑一遍这个实验。比起读十遍「代理循环」四个字，<strong>亲眼看它停下来出计划、再动手、再验证，理解得快得多</strong>。</p><blockquote><p>💡 <strong>一句话总结</strong>：跑一遍这个最小实验，你会亲眼看到「想→做→看」转圈——<strong>尤其是它会自己发现错、自动再来一轮那一下</strong>。</p></blockquote><hr><h2 id="_06-小结" tabindex="-1">06 小结 <a class="header-anchor" href="#_06-小结" aria-label="Permalink to &quot;06 小结&quot;">​</a></h2><p>这一篇就讲清了一件事：<strong>Claude Code 凭什么能自己干活。</strong></p><p>回顾一下核心：</p><table tabindex="0"><thead><tr><th>要点</th><th>一句话记住</th></tr></thead><tbody><tr><td><strong>代理循环</strong></td><td>想→做→看，转圈直到办完；<strong>这是它和聊天框的本质区别</strong></td></tr><tr><td><strong>模型 + 工具</strong></td><td>模型负责想，工具负责做和看</td></tr><tr><td><strong>5 类工具</strong></td><td>文件 / 搜索 / 执行 / 网络 / 代码智能，用哪个它自己挑</td></tr><tr><td><strong>能看到什么</strong></td><td>≈你在那个目录的终端权限，能跨文件协调</td></tr><tr><td><strong>两道安全闸</strong></td><td>检查点（改坏能撤）+ 权限模式（动手前问不问）</td></tr></tbody></table><p>你现在应该能看懂 Claude Code 跑任务时屏幕上在发生什么——它每读一个文件、每跑一条命令，都是循环里的一步；也知道了怎么用 <code>Esc</code> 急停、用计划模式先看方案、靠检查点放心让它改。</p><p><strong>理解了这套机制，你用起来的心态会完全不同</strong>：它不是许愿池，而是个会自己想、动手、检查的搭档——你的活儿是给方向、定验收标准、跑偏时拉一把。</p><hr><p>下一篇 <strong>04 · API 配置</strong>：Claude Code 装好了、原理也懂了，但它得连上模型才能真正干活。下一篇带你把 API 配通——这一步搞定，前面学的循环和工具才能跑起来。</p>`,94)])])}const b=o(r,[["render",a]]);export{u as __pageData,b as default};
